Below is a **complete, self‑contained** example that shows one idiomatic way to expose a C++ iterator from *libpcapng* to OCaml.  
It contains

* the **public OCaml interface** (`pcapng.mli`),  
* the **C‑stub implementation** (`pcapng_stubs.c` – compiled as C++), and  
* a short **README‑style comment** explaining how to build and use the binding.

You can drop the two files into a new directory, add a tiny `dune` file (or a Makefile) and you will have a ready‑to‑use OCaml library called `pcapng`.

---

## 1.  OCaml public interface – `pcapng.mli`

```ocaml
(** pcapng.ml – OCaml bindings for libpcapng

    The library lets you open a pcap‑ng file, walk its frames and
    execute an OCaml function for each frame.

    The implementation is in the companion C++ file
    [pcapng_stubs.c] which builds a thin wrapper around the
    libpcapng C++ iterator.
*)

type t
(** An opaque handle to an opened pcap‑ng file.  The handle is
    automatically closed when it is garbage‑collected, but you can
    close it explicitly with {!close}. *)

type frame = {
  timestamp : float;          (** Seconds since the Unix epoch. *)
  data      : bytes;          (** Raw packet bytes. *)
  length    : int;            (** Length of the captured data. *)
  orig_len  : int;            (** Original length of the packet on the wire. *)
}
(** A single packet (frame) extracted from the pcap‑ng file. *)

val open_file : string -> t
(** Open a pcap‑ng file.  Raises [Failure msg] if the file cannot be opened. *)

val close : t -> unit
(** Close a pcap‑ng handle.  After calling this function the handle must
    not be used again.  The function is idempotent – calling it twice is
    a no‑op. *)

val iter_frames : t -> (frame -> unit) -> unit
(** [iter_frames h f] walks the file associated with handle [h] and calls
    the OCaml function [f] on each frame.  If [f] raises an exception,
    iteration stops and the exception propagates to the caller.

    The callback is invoked **inside the C++ iterator loop**, so the
    runtime lock is released for each frame (see the implementation for
    details). *)

val next_frame : t -> frame option
(** A low‑level alternative to {!iter_frames}.  Returns the next frame
    (or [None] when the end of file is reached).  The function is safe
    to call from OCaml code that needs fine‑grained control over the
    iteration order. *)

(** {1:exceptions Exceptions raised by the binding} *)

exception Error of string
(** Raised when libpcapng reports an error (e.g. malformed file). *)

```

---

## 2.  C/C++ stub implementation – `pcapng_stubs.c`

> **NOTE** – The file must be compiled **as C++**, because libpcapng’s
> iterator is a C++ class.  The `extern "C"` wrappers keep the symbols
> C‑compatible for the OCaml runtime.

```c
/* ----------------------------------------------------------------------
   pcapng_stubs.c – C++ stubs for the OCaml libpcapng bindings
   ---------------------------------------------------------------------- */

#define CAML_NAME_SPACE
#include <caml/mlvalues.h>
#include <caml/memory.h>
#include <caml/alloc.h>
#include <caml/callback.h>
#include <caml/custom.h>
#include <caml/fail.h>
#include <caml/threads.h>

#include <cstring>
#include <string>
#include <exception>

/* libpcapng headers – adjust the include path if necessary */
#include <pcapng/pcapng.h>

/* ----------------------------------------------------------------------
   Helper macros & utilities
   ---------------------------------------------------------------------- */

#define PcapHandle_val(v) (*((pcapng::FileReader **) Data_custom_val(v)))

/* Convert a libpcapng::Frame into an OCaml [frame] record.
   The OCaml layout is:
     0: double   timestamp
     1: bytes    data
     2: int      length
     3: int      orig_len
*/
static value frame_of_pcapng(const pcapng::Frame &fr) {
  CAMLparam0();
  CAMLlocal4(ocaml_frame, timestamp, data, len, orig_len);

  /* 1. timestamp – libpcapng stores it as a 64‑bit integer of microseconds */
  double ts = fr.timestamp() / 1e6;          // convert to seconds
  timestamp = caml_copy_double(ts);

  /* 2. data – copy the raw bytes into an OCaml bytes value */
  size_t n = fr.data().size();
  data = caml_alloc_initialized_string(n, (char *)fr.data().data());

  /* 3. length and original length – both are 32‑bit ints in the C++ API */
  len = Val_int(fr.captured_length());
  orig_len = Val_int(fr.original_length());

  /* 4. Allocate a 4‑field block for the record */
  ocaml_frame = caml_alloc(4, 0);    // tag 0 = a normal block
  Store_field(ocaml_frame, 0, timestamp);
  Store_field(ocaml_frame, 1, data);
  Store_field(ocaml_frame, 2, len);
  Store_field(ocaml_frame, 3, orig_len);

  CAMLreturn(ocaml_frame);
}

/* ----------------------------------------------------------------------
   Custom operations for the opaque handle
   ---------------------------------------------------------------------- */

static void pcap_finalize(value v) {
  pcapng::FileReader *handle = PcapHandle_val(v);
  if (handle != nullptr) {
    delete handle;
    /* Set the pointer to NULL so a later call to [close] becomes a no‑op */
    *((pcapng::FileReader **) Data_custom_val(v)) = nullptr;
  }
}

/* No comparison needed – the value is not meant to be used as a key */
static int pcap_compare(value v1, value v2) { return 0; }

static struct custom_operations pcap_ops = {
  "pcapng.handle",
  pcap_finalize,
  pcap_compare,
  custom_hash_default,
  custom_serialize_default,
  custom_deserialize_default,
  /* The following fields are optional (since OCaml 4.08) */
  custom_fixed_length_default,
  custom_is_no_const_default
};

/* ----------------------------------------------------------------------
   OCaml primitives
   ---------------------------------------------------------------------- */

/* val open_file : string -> t */
CAMLprim value caml_pcapng_open_file(value v_path) {
  CAMLparam1(v_path);
  CAMLlocal1(v_handle);
  const char *path = String_val(v_path);
  pcapng::FileReader *reader = nullptr;

  try {
    reader = new pcapng::FileReader(path);
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  }

  v_handle = caml_alloc_custom(&pcap_ops, sizeof(pcapng::FileReader *), 0, 1);
  PcapHandle_val(v_handle) = reader;
  CAMLreturn(v_handle);
}

/* val close : t -> unit */
CAMLprim value caml_pcapng_close(value v_handle) {
  CAMLparam1(v_handle);
  pcapng::FileReader *reader = PcapHandle_val(v_handle);
  if (reader != nullptr) {
    delete reader;
    PcapHandle_val(v_handle) = nullptr;
  }
  CAMLreturn(Val_unit);
}

/* val next_frame : t -> frame option */
CAMLprim value caml_pcapng_next_frame(value v_handle) {
  CAMLparam1(v_handle);
  CAMLlocal1(v_res);
  pcapng::FileReader *reader = PcapHandle_val(v_handle);
  if (reader == nullptr) caml_failwith("File already closed");

  try {
    if (!reader->has_next()) {
      v_res = Val_int(0);               // None
    } else {
      pcapng::Frame fr = reader->next();
      value ocaml_fr = frame_of_pcapng(fr);
      v_res = caml_alloc(1, 0);         // Some
      Store_field(v_res, 0, ocaml_fr);
    }
  } catch (const std::exception &e) {
    caml_failwith(e.what());
  }
  CAMLreturn(v_res);
}

/* val iter_frames : t -> (frame -> unit) -> unit
   The implementation releases the OCaml runtime lock while walking the
   C++ iterator, but reacquires it for each callback so that the OCaml
   GC can run and the user‑provided closure can raise exceptions.
*/
CAMLprim value caml_pcapng_iter_frames(value v_handle, value v_closure) {
  CAMLparam2(v_handle, v_closure);
  pcapng::FileReader *reader = PcapHandle_val(v_handle);
  if (reader == nullptr) caml_failwith("File already closed");

  /* The callback may allocate or raise; we need a fresh caml local for each
     iteration because the GC may move values. */
  while (true) {
    pcapng::Frame fr;
    bool have_next = false;

    /* --------------------------------------------------------------
       1. Grab the next frame *outside* the OCaml runtime lock.
       -------------------------------------------------------------- */
    caml_release_runtime_system();
    try {
      have_next = reader->has_next();
      if (have_next) fr = reader->next();
    } catch (const std::exception &e) {
      caml_acquire_runtime_system();
      caml_failwith(e.what());
    }
    caml_acquire_runtime_system();

    if (!have_next) break;   // end of file

    /* --------------------------------------------------------------
       2. Convert the C++ frame to an OCaml value.
       -------------------------------------------------------------- */
    CAMLlocal1(v_frame);
    v_frame = frame_of_pcapng(fr);

    /* --------------------------------------------------------------
       3. Invoke the user supplied OCaml closure.
       -------------------------------------------------------------- */
    caml_callback(v_closure, v_frame);
    /* If the closure raises, caml_callback propagates the exception,
       aborting the loop and returning the exception to the caller. */
  }

  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   Registration table (for older OCaml versions; modern build systems
   generate this automatically, but keeping it explicit never hurts)
   ---------------------------------------------------------------------- */
static struct caml_named_value {
  const char *name;
  value (*fn) (value);
} caml_named_values[] = {
  {"pcapng_open_file", caml_pcapng_open_file},
  {"pcapng_close",     caml_pcapng_close},
  {"pcapng_next_frame", caml_pcapng_next_frame},
  {"pcapng_iter_frames", caml_pcapng_iter_frames},
  {NULL, NULL}
};

CAMLprim value caml_register_named_values(value unit) {
  CAMLparam1(unit);
  for (struct caml_named_value *p = caml_named_values; p->name != NULL; ++p)
    caml_register_named_value(p->name, p->fn);
  CAMLreturn(Val_unit);
}

/* ----------------------------------------------------------------------
   End of file
   ---------------------------------------------------------------------- */
```

